mapper.select:
select m.message_id as messageId, m.type as type, ifnull(m.biz_type, m.type) as msgType, m.title as title, m.content as content, m.read_status as readStatus, case when m.read_status = 1 then 1 else 0 end as readFlag, m.biz_type as bizType, m.biz_id as bizId, null as linkUrl, null as linkText, m.create_time as createTime from jst_message m
m.del_flag = '0' and m.user_id = #{userId}
and (m.type = #{query.type} or m.biz_type = #{query.type})
and m.read_status = #{query.readStatus}
order by m.create_time desc, m.message_id desc

mapper.update:
update jst_message
set read_status = 1
where message_id = #{messageId}
  and user_id = #{userId}
  and del_flag = '0'
